export interface LearnLesson {
  title: string;
  slug: string;
  summary: string;
  definition: string;
  examWhy: string;
  example: {
    title: string;
    body: string;
    code?: string;
  };
  trap: string;
  checklist: string[];
  practiceHref: string;
  labHref?: string;
}

export interface LearnTopic {
  title: string;
  slug: string;
  summary: string;
  reviewFile: string;
  lessons: LearnLesson[];
}

function lesson(
  title: string,
  slug: string,
  summary: string,
  definition: string,
  examWhy: string,
  example: LearnLesson["example"],
  trap: string,
  checklist: string[],
  practiceHref: string,
  labHref?: string,
): LearnLesson {
  return { title, slug, summary, definition, examWhy, example, trap, checklist, practiceHref, labHref };
}

